package com.oneil.wellness.walkplanner.calendar.provider.google;
import java.net.URI; import java.time.Duration; import org.springframework.boot.context.properties.ConfigurationProperties; import org.springframework.stereotype.Component;
@Component @ConfigurationProperties(prefix="calendar.google")
public class GoogleCalendarConfiguration {
 private boolean enabled;private String clientId;private String clientSecret;private URI redirectUri;private URI authorizationUri;private URI tokenUri;private URI revocationUri;private URI apiBaseUrl;private Duration connectionTimeout=Duration.ofSeconds(3),readTimeout=Duration.ofSeconds(8);private int maximumEventsPerCalendar=2500;
 public boolean isEnabled(){return enabled;}public void setEnabled(boolean v){enabled=v;}public String getClientId(){return clientId;}public void setClientId(String v){clientId=v;}public String getClientSecret(){return clientSecret;}public void setClientSecret(String v){clientSecret=v;}public URI getRedirectUri(){return redirectUri;}public void setRedirectUri(URI v){redirectUri=v;}public URI getAuthorizationUri(){return authorizationUri;}public void setAuthorizationUri(URI v){authorizationUri=v;}public URI getTokenUri(){return tokenUri;}public void setTokenUri(URI v){tokenUri=v;}public URI getRevocationUri(){return revocationUri;}public void setRevocationUri(URI v){revocationUri=v;}public URI getApiBaseUrl(){return apiBaseUrl;}public void setApiBaseUrl(URI v){apiBaseUrl=v;}public Duration getConnectionTimeout(){return connectionTimeout;}public void setConnectionTimeout(Duration v){connectionTimeout=v;}public Duration getReadTimeout(){return readTimeout;}public void setReadTimeout(Duration v){readTimeout=v;}public int getMaximumEventsPerCalendar(){return maximumEventsPerCalendar;}public void setMaximumEventsPerCalendar(int v){maximumEventsPerCalendar=Math.max(1,Math.min(10000,v));}public boolean isComplete(){return enabled&&clientId!=null&&!clientId.isBlank()&&clientSecret!=null&&!clientSecret.isBlank()&&redirectUri!=null;}
}
